import React, { Component } from "react";
import ProjectDetailsModal from "./ProjectDetailsModal";
import { motion } from "framer-motion";

class Projects extends Component {
  constructor(props) {
    super(props);
    this.state = {
      deps: {},
      detailsModalShow: false,
      isVisible: false
    };

    this.sectionRef = React.createRef();
  }

  componentDidMount() {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          this.setState({ isVisible: true });
        }
      },
      { threshold: 0.2 }
    );

    if (this.sectionRef.current) {
      observer.observe(this.sectionRef.current);
    }
  }

  render() {
    let detailsModalShow = (data) => {
      this.setState({ detailsModalShow: true, deps: data });
    };

    let detailsModalClose = () =>
      this.setState({ detailsModalShow: false });

    if (this.props.resumeProjects && this.props.resumeBasicInfo) {
      var sectionName = this.props.resumeBasicInfo.section_name.projects;

      var projects = this.props.resumeProjects.map((projects, i) => {
        return (
          <motion.div
            className="col-sm-12 col-md-6 col-lg-4"
            key={projects.title}
            style={{ cursor: "pointer" }}
            initial={{ opacity: 0, y: 50 }}
            animate={
              this.state.isVisible
                ? { opacity: 1, y: 0 }
                : { opacity: 0, y: 50 }
            }
            transition={{ duration: 0.6, delay: i * 0.15 }}
          >
            <span className="portfolio-item d-block">
              <div
                className="foto"
                onClick={() => detailsModalShow(projects)}
              >
                <div
                  style={{
                    height: "230px",
                    padding: "15px",
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "flex-start",
                    borderRadius: "8px"
                  }}
                >
                  {/* Date */}
                  <span className="project-date">
                    {projects.startDate}
                  </span>

                  {/* Title */}
                  <p className="project-title-settings mt-2">
                    {projects.title}
                  </p>

                  {/* Description */}
                  <p
                    style={{
                      fontSize: "14px",
                      textAlign: "justify",
                      marginTop: "10px"
                    }}
                  >
                    {projects.description}
                  </p>
                </div>
              </div>
            </span>
          </motion.div>
        );
      });
    }

    return (
      <section id="portfolio" ref={this.sectionRef}>
        <div className="col-md-12">

          {/* Title */}
          <h1 className="section-title" style={{ color: "black" }}>
            <span>{sectionName}</span>
          </h1>

          <div className="col-md-12 mx-auto">
            <div className="row mx-auto">{projects}</div>
          </div>

          <ProjectDetailsModal
            show={this.state.detailsModalShow}
            onHide={detailsModalClose}
            data={this.state.deps}
          />
        </div>
      </section>
    );
  }
}

export default Projects;
